function generateGif(): Buffer {
  // 1x1 透明 GIF89a
  return Buffer.from(
    "GIF89a" +
      "\x01\x00\x01\x00\x00\x00\x00" +
      "\x21\xf9\x04\x00\x00\x00\x00\x00" +
      "," +
      "\x00\x00\x00\x00\x01\x00\x01\x00\x00" +
      "\x02\x02\x44\x01\x00\x3b",
    "binary"
  );
}

function generateBmp(): Buffer {
  // 1x1 24-bit BMP
  const pixelData = Buffer.from([0xff, 0x00, 0x00]); // BGR red
  const rowSize = 4; // padded to 4 bytes
  const pixelDataSize = rowSize;
  const headerSize = 54;
  const fileSize = headerSize + pixelDataSize;
  const buf = Buffer.alloc(fileSize);
  // BMP file header
  buf.write("BM", 0);
  buf.writeUInt32LE(fileSize, 2);
  buf.writeUInt32LE(0, 6);
  buf.writeUInt32LE(headerSize, 10);
  // DIB header
  buf.writeUInt32LE(40, 14);
  buf.writeInt32LE(1, 18);
  buf.writeInt32LE(1, 22);
  buf.writeUInt16LE(1, 26);
  buf.writeUInt16LE(24, 28);
  buf.writeUInt32LE(0, 30);
  buf.writeUInt32LE(pixelDataSize, 34);
  buf.writeInt32LE(2835, 38);
  buf.writeInt32LE(2835, 42);
  buf.writeUInt32LE(0, 46);
  buf.writeUInt32LE(0, 50);
  // pixel data (bottom-up)
  pixelData.copy(buf, headerSize);
  buf.fill(0, headerSize + 3, headerSize + 4); // padding
  return buf;
}

function generateWorkbooks() {
  const wb = XLSX.utils.book_new();
  const salesData = [
    ["姓名", "销售额", "日期", "备注"],
    ["张三", 1200, new Date("2026-01-05T00:00:00Z"), null],
    ["李四", 980.5, new Date("2026-01-06T00:00:00Z"), "已回款"],
    ["王五", 1500, new Date("2026-01-07T00:00:00Z"), "待确认"],
    [null, null, null, null], // 中间空白行
    ["赵六", 2000, new Date("2026-01-08T00:00:00Z"), null],
    [null, null, null, null], // 尾部空白行（应被裁剪）
    [null, null, null, null], // 尾部空白行（应被裁剪）
  ];
  const ws1 = XLSX.utils.aoa_to_sheet(salesData);
  XLSX.utils.book_append_sheet(wb, ws1, "一月");
  const ws2 = XLSX.utils.aoa_to_sheet([]);
  XLSX.utils.book_append_sheet(wb, ws2, "二月");
  XLSX.writeFile(wb, path.join(fixturesDir, "sales.xlsx"));
  XLSX.writeFile(wb, path.join(fixturesDir, "legacy.xls"), { bookType: "biff8" });

  // CSV 手动写出 UTF-8（不带 BOM），避免 SheetJS 读入 BOM 后解析异常
  const csvLines = [
    ["姓名", "销售额", "日期"],
    ["张三", 1200, "2026-01-05T00:00:00.000Z"],
    ["李四, 经理", 980.5, "2026-01-06T00:00:00.000Z"],
  ];
  const csvContent = csvLines
    .map((row) =>
      row
        .map((cell) => {
          const s = String(cell);
          return s.includes(",") ? `"${s.replace(/"/g, '""')}"` : s;
        })
        .join(",")
    )
    .join("\n");
  fs.writeFileSync(path.join(fixturesDir, "data.csv"), csvContent, "utf8");

  // 损坏文件：截断的 zip（xlsx 本质是 zip），SheetJS 无法解析
  fs.writeFileSync(
    path.join(fixturesDir, "corrupt.xlsx"),
    Buffer.from([0x50, 0x4b, 0x03, 0x04, 0xff, 0xff, 0xff, 0xff])
  );

  // 不支持的扩展名样本
  fs.writeFileSync(path.join(fixturesDir, "notes.txt"), "not a spreadsheet");
}

function generateImages() {
  fs.writeFileSync(path.join(fixturesDir, "img.png"), generatePng());
  fs.writeFileSync(path.join(fixturesDir, "img.jpg"), generateJpg());
  fs.writeFileSync(path.join(fixturesDir, "img.jpeg"), generateJpg());
  fs.writeFileSync(path.join(fixturesDir, "img.gif"), generateGif());
  fs.writeFileSync(path.join(fixturesDir, "img.bmp"), generateBmp());
}

function main() {
  fs.mkdirSync(fixturesDir, { recursive: true });
  generateWorkbooks();
  generateImages();
  console.error("fixtures generated in", fixturesDir);
}

main();
